#include <stdio.h>
#include <stdlib.h>

// Structure to represent a cell
typedef struct Cell {
    int row;
    int col;
    int effort;
} Cell;

// Compare function for priority queue
int compare(const void *a, const void *b) {
    Cell *cell1 = (Cell *)a;
    Cell *cell2 = (Cell *)b;
    return cell1->effort - cell2->effort;
}

// Function to find the minimum effort path
int minimumEffort(int **heights, int rows, int cols) {
    // Create a priority queue
    Cell *pq = (Cell *)malloc(rows * cols * sizeof(Cell));
    int pqSize = 0;

    // Create a distance matrix
    int **dist = (int **)malloc(rows * sizeof(int *));
    for (int i = 0; i < rows; i++) {
        dist[i] = (int *)malloc(cols * sizeof(int));
        for (int j = 0; j < cols; j++) {
            dist[i][j] = INT_MAX;
        }
    }
    dist[0][0] = 0;

    // Add the source cell to the priority queue
    pq[pqSize].row = 0;
    pq[pqSize].col = 0;
    pq[pqSize].effort = 0;
    pqSize++;

    // Define the possible directions
    int dr[] = {-1, 0, 1, 0};
    int dc[] = {0, 1, 0, -1};

    // Start the Dijkstra algorithm
    while (pqSize > 0) {
        // Sort the priority queue
        qsort(pq, pqSize, sizeof(Cell), compare);

        // Get the cell with the minimum effort
        Cell current = pq[0];
        pqSize--;
        for (int i = 0; i < pqSize; i++) {
            pq[i] = pq[i + 1];
        }

        // If we reach the destination cell, return the current effort
        if (current.row == rows - 1 && current.col == cols - 1) {
            return current.effort;
        }

        // Check all 4 possible adjacent cells
        for (int i = 0; i < 4; i++) {
            int newr = current.row + dr[i];
            int newc = current.col + dc[i];

            // Check if the new cell is within bounds
            if (newr >= 0 && newc >= 0 && newr < rows && newc < cols) {
                // Calculate the effort required to move to the new cell
                int newEffort = current.effort;
                if (heights[newr][newc] > heights[current.row][current.col]) {
                    newEffort = heights[newr][newc] - heights[current.row][current.col];
                }

                // If the calculated effort is less, update and push to the queue
                if (newEffort < dist[newr][newc]) {
                    dist[newr][newc] = newEffort;
                    pq[pqSize].row = newr;
                    pq[pqSize].col = newc;
                    pq[pqSize].effort = newEffort;
                    pqSize++;
                }
            }
        }
    }
    return 0;
}

int main() {
    int rows = 3;
    int cols = 3;
    int **heights = (int **)malloc(rows * sizeof(int *));
    for (int i = 0; i < rows; i++) {
        heights[i] = (int *)malloc(cols * sizeof(int));
    }
    heights[0][0] = 1;
    heights[0][1] = 2;
    heights[0][2] = 3;
    heights[1][0] = 4;
    heights[1][1] = 5;
    heights[1][2] = 6;
    heights[2][0] = 7;
    heights[2][1] = 8;
    heights[2][2] = 9;

    int ans = minimumEffort(heights, rows, cols);
    printf("%d\n", ans);

    return 0;
}

